import React, { useCallback, useEffect, useState } from 'react';
import { hasPermissionCode, usePeriodJobPermissions } from '../../../hooks/usePeriodJobPermissions';
import { periodPageLabels as L } from '../../../constants/periodPageLabels';
import { PeriodActionPanel } from '../../../components/kt/PeriodActionPanel';
import { PeriodCloseChecklistSection } from '../../../components/kt/PeriodCloseChecklistSection';
import { ktService } from '../../../services/kt/ktService';
import type { PeriodCloseChecklistDto } from '../../../services/kt/models';

const CloseChecklistBlock: React.FC<{
  month: number;
  year: number;
  testIdPrefix: string;
  onChecklist: (checklist: PeriodCloseChecklistDto | null) => void;
}> = ({ month, year, testIdPrefix, onChecklist }) => {
  const [checklist, setChecklist] = useState<PeriodCloseChecklistDto | null>(null);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    let cancelled = false;
    const t = setTimeout(() => {
      setLoading(true);
      ktService.getPeriodCloseChecklist(month, year)
        .then(data => {
          if (!cancelled) {
            setChecklist(data);
            onChecklist(data);
          }
        })
        .catch(() => {
          if (!cancelled) {
            setChecklist(null);
            onChecklist(null);
          }
        })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [month, year, onChecklist]);

  return (
    <PeriodCloseChecklistSection
      checklist={checklist}
      loading={loading}
      testIdPrefix={testIdPrefix}
    />
  );
};

const DongSoPage: React.FC = () => {
  const { canRun } = usePeriodJobPermissions('period-close-final');
  void hasPermissionCode;
  const [canClose, setCanClose] = useState(false);
  const handleChecklist = useCallback((c: PeriodCloseChecklistDto | null) => {
    setCanClose(c?.canClose ?? false);
  }, []);

  return (
    <PeriodActionPanel
      testIdPrefix="kt-dong-so"
      title={L.dongSo.title}
      icon="fa-lock"
      description={L.dongSo.description}
      runLabel={L.dongSo.runLabel}
      runDisabledExtra={!canClose}
      runPermitted={canRun}
      onRun={(m, y) => ktService.closePeriodFinal(m, y)}
      renderExtra={({ month, year }) => (
        <CloseChecklistBlock
          month={month}
          year={year}
          testIdPrefix="kt-dong-so"
          onChecklist={handleChecklist}
        />
      )}
    />
  );
};

export default DongSoPage;
